mapper.update:
update faq_tbl set
	faq_title = #{faqTitle},
	faq_content = #{faqContent},
	faq_category = #{faqCategory}
where faq_no = #{faqNo}

mapper.select:
select m.member_id, m.member_name, m.member_nickname, m.member_email, m.member_grade, m.member_thumb, m.member_status, to_char(m.enroll_date, 'YYYY-MM-DD') as enrollDate, m.lock_reason, m.lock_until, -- 게시글/댓글/신고 수는 서브쿼리로 각각 카운트 (select count(*) from board_tbl b where b.writer_id = m.member_id) as boardCount, (select count(*) from board_comment_tbl c where c.board_comment_writer = m.member_id) as commentCount, (select count(*) from report_tbl r join board_tbl b on r.target_no = b.board_no where b.writer_id = m.member_id) as reportCount, (select count(*) from member_log_tbl l where l.member_id = m.member_id and l.log_action = '로그인실패' and l.log_time >= sysdate - 1) as failCount, (select count(*) from member_log_tbl l where l.member_id = m.member_id and l.log_alert = '위치변경' and l.log_time >= sysdate - 1) as locationChangeCount, -- 가장 최근 로그인/로그아웃 액션이 '로그인'이면 접속중, '로그아웃'이면 미접속 -- log_time이 같은 초(DATE 타입)면 member_log_no로 tiebreaker 걸어서 가장 최신 row 확정 (case when ( select log_action from ( select log_action from member_log_tbl where member_id = m.member_id and log_action in ('로그인', '로그아웃') order by log_time desc, member_log_no desc ) where rownum = 1 ) = '로그인' then 1 else 0 end) as isOnline from member_tbl1 m
m.member_status = #{status}
and m.member_grade = #{grade}
and (m.member_id like '%'||#{keyword}||'%' or m.member_name like '%'||#{keyword}||'%')
order by m.enroll_date desc


select * from (
	select member_log_no, log_ip, log_time, log_action, log_detail
	from member_log_tbl
	where member_id = #{memberId}
	order by log_time desc
) where rownum <= 4

select member_log_no, log_ip, log_time, log_action, log_detail, log_device, log_location, log_result, log_alert from member_log_tbl where member_id = #{memberId}
and log_action = #{action}
and log_result = #{result}
order by log_time ${sort} offset #{start} rows fetch next 20 rows only

mapper.update:
update board_tbl set board_status =
1 2
where board_no = #{targetNo}

update board_comment_tbl set board_comment_status =

		1

where board_comment_no = #{targetNo}

update member_tbl1 set
lock_until = sysdate + 1, member_status = 3, lock_until = sysdate + 3, member_status = 3, lock_until = sysdate + 7, member_status = 3, member_status = 1,
lock_reason = #{lockReason} where member_id = #{targetId}

update report_tbl set
	report_status = 1
where target_no = #{targetNo} and target_type = #{targetType}
